const useResponsive = () => {
  const [w, setW] = useState(window.innerWidth)
  useEffect(() => {
    const h = () => setW(window.innerWidth)
    window.addEventListener('resize', h)
    window.addEventListener('orientationchange', () => setTimeout(h, 100))
    return () => { window.removeEventListener('resize', h); window.removeEventListener('orientationchange', h) }
  }, [])
  return { isMobile: w < 768 }
}

const inputBase = (focused) => ({
  width: '100%', padding: '10px 12px',
  backgroundColor: focused ? DS.color.surface : DS.color.surfaceAlt,
  border: `1.5px solid ${focused ? DS.color.primary : DS.color.borderLight}`,
  borderRadius: DS.radius, fontSize: '14px', fontFamily: DS.font, fontWeight: 400,
  color: DS.color.graphite, outline: 'none', transition: 'all 150ms ease',
  boxShadow: focused ? `0 0 0 3px ${DS.color.primaryGlow}` : 'none',
  boxSizing: 'border-box', WebkitAppearance: 'none',
})

const DSInput = ({ label, type = 'text', value, onChange, placeholder, style: s, ...rest }) => {
  const [f, setF] = useState(false)
  return (
    <div style={{ minWidth: 0, flex: 1, ...s }}>
      {label && <label style={{ display: 'block', fontFamily: DS.font, fontSize: '11px', fontWeight: 600, color: f ? DS.color.primary : DS.color.graphiteLight, textTransform: 'uppercase', letterSpacing: '0.04em', marginBottom: '4px' }}>{label}</label>}
      <input type={type} value={value} onChange={onChange} placeholder={placeholder}
        onFocus={() => setF(true)} onBlur={() => setF(false)} style={{ ...inputBase(f) }} {...rest} />
    </div>
  )
}

const DSSelect = ({ label, value, onChange, children, style: s }) => {
  const [f, setF] = useState(false)
  return (
    <div style={{ minWidth: 0, flex: 1, ...s }}>
      {label && <label style={{ display: 'block', fontFamily: DS.font, fontSize: '11px', fontWeight: 600, color: f ? DS.color.primary : DS.color.graphiteLight, textTransform: 'uppercase', letterSpacing: '0.04em', marginBottom: '4px' }}>{label}</label>}
      <select value={value} onChange={onChange} onFocus={() => setF(true)} onBlur={() => setF(false)}
        style={{ ...inputBase(f), cursor: 'pointer', appearance: 'none', MozAppearance: 'none',
          backgroundImage: `url("data:image/svg+xml,%3Csvg width='10' height='6' viewBox='0 0 10 6' xmlns='http://www.w3.org/2000/svg'%3E%3Cpath d='M1 1l4 4 4-4' stroke='%2395A39D' stroke-width='1.5' fill='none'/%3E%3C/svg%3E")`,
          backgroundRepeat: 'no-repeat', backgroundPosition: 'right 10px center', paddingRight: '28px',
        }}>{children}</select>
    </div>
  )
}

const DSButton = ({ children, onClick, disabled, variant = 'primary', icon, size = 'md', style: s }) => {
  const vars = {
    primary: { bg: DS.color.primary, color: '#fff', border: 'none' },
    danger: { bg: DS.color.danger, color: '#fff', border: 'none' },
    info: { bg: DS.color.info, color: '#fff', border: 'none' },
    warning: { bg: DS.color.warning, color: '#fff', border: 'none' },
    ghost: { bg: DS.color.pendingBg, color: DS.color.graphiteMed, border: `1px solid ${DS.color.borderLight}` },
    outline: { bg: 'transparent', color: DS.color.primary, border: `1.5px solid ${DS.color.primary}` },
    outlineDanger: { bg: 'transparent', color: DS.color.danger, border: `1.5px solid ${DS.color.danger}` },
  }
  const sizes = { sm: { p: '6px 12px', fs: '11px', mh: '30px' }, md: { p: '10px 18px', fs: '13px', mh: '40px' }, lg: { p: '14px 32px', fs: '15px', mh: '48px' } }
  const v = vars[variant] || vars.primary
  const sz = sizes[size] || sizes.md
  return (
    <button onClick={onClick} disabled={disabled} style={{
      display: 'inline-flex', alignItems: 'center', justifyContent: 'center', gap: '6px',
      padding: sz.p, backgroundColor: disabled ? DS.color.graphiteMuted : v.bg,
      color: disabled ? '#fff' : v.color, border: disabled ? 'none' : v.border,
      borderRadius: DS.radius, fontFamily: DS.font, fontSize: sz.fs, fontWeight: 600,
      cursor: disabled ? 'not-allowed' : 'pointer', transition: 'all 150ms', minHeight: sz.mh, ...s,
    }}>
      {icon && <Icon name={icon} size={size === 'sm' ? 12 : 14} color={disabled ? '#fff' : v.color} />}
      {children}
    </button>
  )
}

const SectionHeader = ({ icon, title, color = DS.color.primary, bg = DS.color.cardHeader, right }) => (
  <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '10px 16px', backgroundColor: bg, borderBottom: `1px solid ${DS.color.borderLight}` }}>
    <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
      {icon && <Icon name={icon} size={18} color={color} />}
      <span style={{ fontFamily: DS.font, fontSize: '13px', fontWeight: 700, color, textTransform: 'uppercase', letterSpacing: '0.03em' }}>{title}</span>
    </div>
    {right}
  </div>
)

const Card = ({ children, style: s, ...rest }) => (
  <div style={{ backgroundColor: DS.color.surface, borderRadius: DS.radius, boxShadow: DS.shadow.sm, border: `1px solid ${DS.color.borderLight}`, overflow: 'hidden', animation: 'ctrlFadeIn 0.4s ease', ...s }} {...rest}>{children}</div>
)

/* ═══════════════════════════════════════════════════════════════
   LOGIN SCREEN
   ═══════════════════════════════════════════════════════════════ */
const LoginScreen = ({ onLogin }) => {
  const { isMobile } = useResponsive()
  const [email, setEmail] = useState('')
  const [password, setPassword] = useState('')
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState('')
  const [rememberLogin, setRememberLogin] = useState(false)

  useEffect(() => {
    const se = localStorage.getItem('userEmail'), sp = localStorage.getItem('userPassword')
    if (se && sp) { setEmail(se); setPassword(sp); setRememberLogin(true) }
  }, [])

  const handleLogin = async (e) => {
    e.preventDefault(); setLoading(true); setError('')
    const result = await onLogin(email, password)
    if (result.error) setError(result.error.message)
    else { if (rememberLogin) { localStorage.setItem('userEmail', email); localStorage.setItem('userPassword', password) } else { localStorage.removeItem('userEmail'); localStorage.removeItem('userPassword') } }
    setLoading(false)
  }

  return (
    <>
      <style>{GLOBAL_CSS}</style>
      <div style={{ minHeight: '100vh', backgroundColor: DS.color.bg, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '20px', fontFamily: DS.font }}>
        <div style={{ maxWidth: '440px', width: '100%', animation: 'ctrlFadeIn 0.5s ease' }}>
          {/* Logo + Title card — matches production sheet headers */}
          <div style={{ backgroundColor: DS.color.surface, borderRadius: DS.radius, boxShadow: DS.shadow.md, overflow: 'hidden', border: `1px solid ${DS.color.borderLight}` }}>
            <div style={{ backgroundColor: DS.color.graphite, padding: '32px 24px', display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '14px' }}>
              <img src={LOGO_URL} alt="Aladin Foods" style={{ height: '48px', objectFit: 'contain' }} onError={e => { e.target.style.display = 'none' }} />
              <div style={{ textAlign: 'center' }}>
                <h1 style={{ margin: 0, fontSize: '20px', fontWeight: 700, color: '#FFFFFF', fontFamily: DS.font, letterSpacing: '-0.01em', textTransform: 'uppercase' }}>Control Room</h1>
                <p style={{ margin: '4px 0 0', fontSize: '11px', fontWeight: 500, color: 'rgba(255,255,255,0.45)', fontFamily: DS.font, letterSpacing: '0.06em', textTransform: 'uppercase' }}>Система за управление на чек листи</p>
              </div>
            </div>

            <form onSubmit={handleLogin} style={{ padding: '28px 24px' }}>
              {error && (
                <div style={{ backgroundColor: DS.color.dangerBg, padding: '10px 14px', marginBottom: '16px', fontSize: '12px', fontFamily: DS.font, fontWeight: 500, color: DS.color.danger, border: `1px solid ${DS.color.danger}`, display: 'flex', alignItems: 'center', gap: '8px' }}>
                  <Icon name="alert" size={16} color={DS.color.danger} />{error}
                </div>
              )}
              <div style={{ marginBottom: '14px' }}><DSInput label="Имейл" type="email" value={email} onChange={e => setEmail(e.target.value)} placeholder="email@example.com" required /></div>
              <div style={{ marginBottom: '14px' }}><DSInput label="Парола" type="password" value={password} onChange={e => setPassword(e.target.value)} placeholder="••••••••" required /></div>
              <label style={{ display: 'flex', alignItems: 'center', gap: '8px', cursor: 'pointer', fontFamily: DS.font, fontSize: '12px', color: DS.color.graphiteMed, marginBottom: '20px', fontWeight: 500 }}>
                <input type="checkbox" checked={rememberLogin} onChange={e => setRememberLogin(e.target.checked)} style={{ accentColor: DS.color.primary, width: '16px', height: '16px' }} />
                Запомни данните ми
              </label>
              <button type="submit" disabled={loading} style={{
                width: '100%', padding: '14px', border: 'none', borderRadius: DS.radius,
                backgroundColor: loading ? DS.color.graphiteMuted : DS.color.primary,
                color: '#fff', fontFamily: DS.font, fontSize: '15px', fontWeight: 700,
                cursor: loading ? 'not-allowed' : 'pointer', transition: 'all 200ms',
                animation: !loading ? 'ctrlBreathe 3s ease-in-out infinite' : 'none',
                display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px',
              }}>
                <Icon name="lock" size={16} color="#fff" />
                {loading ? 'Вход...' : 'Вход в системата'}
              </button>
            </form>
          </div>
          <div style={{ textAlign: 'center', padding: '16px', fontFamily: DS.font, fontSize: '10px', color: DS.color.graphiteMuted, fontWeight: 500 }}>© 2026 Aladin Foods | by MG</div>
        </div>
      </div>
    </>
  )
}

