/* ═══════════════════════════════════════════════════════════════
   SUPER ADMIN PANEL
   ═══════════════════════════════════════════════════════════════ */
const SuperAdminPanel = ({ onBack }) => {
  useNavigationHistory(onBack)
  const { isMobile } = useResponsive()
  const pad = isMobile ? '12px' : '20px'

  const [activeTab, setActiveTab] = useState('managers')
  const [loading, setLoading] = useState(false)
  const [emailList, setEmailList] = useState('')
  const [creationResults, setCreationResults] = useState([])
  const [allManagers, setAllManagers] = useState([])
  const [selectedManager, setSelectedManager] = useState(null)
  const [newPassword, setNewPassword] = useState('')
  const [editingRestaurant, setEditingRestaurant] = useState(null)
  const [newRestaurantName, setNewRestaurantName] = useState('')
  const [templates, setTemplates] = useState([])
  const [templateName, setTemplateName] = useState('')
  const [templateDescription, setTemplateDescription] = useState('')
  const [templateConfig, setTemplateConfig] = useState('')
  const [selectedDepartments, setSelectedDepartments] = useState([])
  const [restaurants, setRestaurants] = useState([])
  const [selectedRestaurant, setSelectedRestaurant] = useState(null)
  const [availableTemplates, setAvailableTemplates] = useState([])
  const [assignedTemplates, setAssignedTemplates] = useState([])
  const departments = ['Pizza', 'Chicken', 'Doner', 'Operations']

  useEffect(() => { if (activeTab === 'manage') loadAllManagers(); else if (activeTab === 'templates') loadTemplates(); else if (activeTab === 'assign') { loadRestaurants(); loadTemplates() } }, [activeTab])

  const loadAllManagers = async () => { const { data, error } = await supabase.from('profiles').select('*, restaurants(*)').eq('role', 'manager').order('created_at', { ascending: false }); if (!error) setAllManagers(data || []); else console.error('Load managers error:', error) }
  const loadTemplates = async () => { const { data } = await supabase.from('checklist_templates').select('*, template_departments(department_name)').order('created_at', { ascending: false }); if (data) setTemplates(data) }
  const loadRestaurants = async () => { const { data } = await supabase.from('restaurants').select('*').eq('active', true).order('name'); if (data) setRestaurants(data) }
  const loadAssignedTemplates = async (rid) => { const { data } = await supabase.from('restaurant_templates').select('*, checklist_templates(id, name)').eq('restaurant_id', rid); if (data) { setAssignedTemplates(data); setAvailableTemplates(templates.filter(t => !data.map(d => d.template_id).includes(t.id))) } }
  const generatePassword = () => { const c = 'ABCDEFGHJKMNPQRSTUVWXYZabcdefghjkmnpqrstuvwxyz23456789'; return Array.from({ length: 8 }, () => c[Math.floor(Math.random() * c.length)]).join('') }

  const handleCreateManagers = async () => { setLoading(true); setCreationResults([]); const emails = emailList.split('\n').map(e => e.trim()).filter(e => e); const results = []; for (const email of emails) { const pw = generatePassword(); const r = await createNewManager(email, pw, email.split('@')[0]); results.push({ email, password: pw, success: r.success, message: r.success ? 'Успешно създаден' : r.error }) }; setCreationResults(results); setLoading(false) }
  const downloadCSV = () => { const csv = 'Email,Password,Status,Message\n' + creationResults.map(r => `${r.email},${r.password},${r.success ? 'Success' : 'Error'},${r.message}`).join('\n'); const blob = new Blob(['\uFEFF' + csv], { type: 'text/csv;charset=utf-8' }); const url = URL.createObjectURL(blob); const a = document.createElement('a'); a.href = url; a.download = `managers_${new Date().toISOString().split('T')[0]}.csv`; a.click(); URL.revokeObjectURL(url) }
  const handleResetPassword = async () => { if (!selectedManager || !newPassword) { alert('Моля избери мениджър и въведи нова парола'); return }; if (newPassword.length < 6) { alert('Паролата трябва да е поне 6 символа'); return }; setLoading(true); const r = await resetManagerPassword(selectedManager.id, newPassword); setLoading(false); if (r.success) { alert(`Паролата на ${selectedManager.email} е променена!\nНова парола: ${newPassword}`); setNewPassword(''); setSelectedManager(null) } else alert('Грешка: ' + r.error) }
  const handleUpdateRestaurantName = async () => { if (!editingRestaurant?.id || !newRestaurantName.trim()) { alert('Моля въведи име'); return }; setLoading(true); try { const { error } = await supabase.from('restaurants').update({ name: newRestaurantName.trim() }).eq('id', editingRestaurant.id); if (error) throw error; alert('Името е променено!'); setEditingRestaurant(null); setNewRestaurantName(''); loadAllManagers() } catch (e) { alert('Грешка: ' + e.message) } finally { setLoading(false) } }
  const handleCreateTemplate = async () => { if (!templateName || !templateConfig || selectedDepartments.length === 0) { alert('Моля попълни всички полета'); return }; try { const cfg = JSON.parse(templateConfig); setLoading(true); const { data: t, error: e1 } = await supabase.from('checklist_templates').insert({ name: templateName, description: templateDescription, config: cfg, active: true, created_by: (await supabase.auth.getUser()).data.user.id }).select().single(); if (e1) throw e1; const { error: e2 } = await supabase.from('template_departments').insert(selectedDepartments.map(d => ({ template_id: t.id, department_name: d }))); if (e2) throw e2; alert('Template създаден!'); setTemplateName(''); setTemplateDescription(''); setTemplateConfig(''); setSelectedDepartments([]); loadTemplates() } catch (e) { alert('Грешка: ' + e.message) } finally { setLoading(false) } }
  const handleAssignTemplate = async (tid) => { if (!selectedRestaurant) return; try { const { error } = await supabase.from('restaurant_templates').insert({ restaurant_id: selectedRestaurant.id, template_id: tid, enabled: true, assigned_by: (await supabase.auth.getUser()).data.user.id }); if (error) throw error; loadAssignedTemplates(selectedRestaurant.id) } catch (e) { alert('Грешка: ' + e.message) } }
  const handleUnassignTemplate = async (aid) => { try { const { error } = await supabase.from('restaurant_templates').delete().eq('id', aid); if (error) throw error; loadAssignedTemplates(selectedRestaurant.id) } catch (e) { alert('Грешка: ' + e.message) } }

  const tabs = [{ id: 'managers', label: 'Създай', icon: 'users' }, { id: 'manage', label: 'Управление', icon: 'settings' }, { id: 'templates', label: 'Templates', icon: 'clipboard' }, { id: 'assign', label: 'Разпределяне', icon: 'link' }]

  return (
    <>
      <style>{GLOBAL_CSS}</style>
      <div style={{ minHeight: '100vh', backgroundColor: DS.color.bg, fontFamily: DS.font, color: DS.color.graphite, display: 'flex', flexDirection: 'column' }}>
        {/* ═══ DARK TOP BAR ═══ */}
        <div style={{ position: 'sticky', top: 0, zIndex: 100, backgroundColor: DS.color.graphite, padding: '0 16px', display: 'flex', alignItems: 'center', justifyContent: 'space-between', height: '48px', boxShadow: '0 2px 8px rgba(0,0,0,0.2)' }}>
          <button onClick={onBack} style={{ display: 'flex', alignItems: 'center', gap: '4px', padding: '6px 10px', backgroundColor: 'rgba(255,255,255,0.08)', border: '1px solid rgba(255,255,255,0.12)', borderRadius: DS.radius, color: 'white', fontSize: '12px', fontFamily: DS.font, fontWeight: 600, cursor: 'pointer' }}>
            <Icon name="back" size={14} color="white" /> Назад
          </button>
          <span style={{ fontFamily: DS.font, fontSize: '12px', fontWeight: 700, color: 'rgba(255,255,255,0.6)', letterSpacing: '0.06em', textTransform: 'uppercase' }}>Super Admin Panel</span>
          <div style={{ width: 60 }} />
        </div>

        <div style={{ maxWidth: '1200px', margin: '0 auto', padding: pad, flex: 1, width: '100%' }}>
          {/* ═══ LOGO + TITLE ═══ */}
          <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '16px', padding: '0 2px' }}>
            <img src={LOGO_URL} alt="Aladin Foods" style={{ height: isMobile ? '36px' : '48px', objectFit: 'contain' }} onError={e => { e.target.style.display = 'none' }} />
            <div>
              <h1 style={{ margin: 0, fontFamily: DS.font, fontSize: isMobile ? '16px' : '22px', fontWeight: 700, color: DS.color.primary, letterSpacing: '-0.01em', textTransform: 'uppercase' }}>Администрация</h1>
              <p style={{ margin: '2px 0 0', fontFamily: DS.font, fontSize: '12px', color: DS.color.graphiteMuted, fontWeight: 500 }}>Управление на мениджъри, templates и ресторанти</p>
            </div>
          </div>

          {/* Tabs */}
          <Card style={{ marginBottom: '16px' }}>
            <div style={{ display: 'flex', overflowX: 'auto' }}>
              {tabs.map(tab => (
                <button key={tab.id} onClick={() => setActiveTab(tab.id)} style={{
                  display: 'flex', alignItems: 'center', gap: '6px', padding: isMobile ? '10px 14px' : '12px 20px',
                  backgroundColor: activeTab === tab.id ? DS.color.primary : 'transparent',
                  color: activeTab === tab.id ? '#fff' : DS.color.graphiteMed,
                  border: 'none', cursor: 'pointer', fontFamily: DS.font,
                  fontSize: isMobile ? '11px' : '13px', fontWeight: 600, whiteSpace: 'nowrap', transition: 'all 150ms',
                  borderBottom: activeTab === tab.id ? 'none' : `2px solid ${DS.color.borderLight}`,
                }}>
                  <Icon name={tab.icon} size={14} color={activeTab === tab.id ? '#fff' : DS.color.graphiteMuted} />{tab.label}
                </button>
              ))}
            </div>
          </Card>

          {/* ═══ TAB: CREATE MANAGERS ═══ */}
          {activeTab === 'managers' && (
            <Card>
              <SectionHeader icon="users" title="Създаване на мениджъри" />
              <div style={{ padding: pad }}>
                <label style={{ display: 'block', fontFamily: DS.font, fontSize: '11px', fontWeight: 600, color: DS.color.graphiteLight, textTransform: 'uppercase', letterSpacing: '0.04em', marginBottom: '6px' }}>Email адреси (по един на ред):</label>
                <textarea value={emailList} onChange={e => setEmailList(e.target.value)} placeholder={'manager1@restaurant.com\nmanager2@restaurant.com'}
                  style={{ ...inputBase(false), minHeight: '140px', resize: 'vertical', fontFamily: "'DM Sans', monospace", marginBottom: '16px' }} />
                <DSButton onClick={handleCreateManagers} disabled={loading || !emailList.trim()} icon="plus">{loading ? 'Създаване...' : 'Създай мениджъри'}</DSButton>

                {creationResults.length > 0 && (
                  <div style={{ marginTop: '24px', animation: 'slideUp 0.3s ease' }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '10px' }}>
                      <span style={{ fontFamily: DS.font, fontSize: '11px', fontWeight: 700, color: DS.color.primary, textTransform: 'uppercase', letterSpacing: '0.04em' }}>Резултати ({creationResults.length})</span>
                      <DSButton onClick={downloadCSV} variant="outline" icon="download" size="sm">CSV</DSButton>
                    </div>
                    <div style={{ overflowX: 'auto' }}>
                      <table style={{ width: '100%', borderCollapse: 'collapse', fontFamily: DS.font, fontSize: '12px' }}>
                        <thead><tr style={{ backgroundColor: DS.color.cardHeader }}>{['Email', 'Парола', 'Статус', 'Съобщение'].map(h => <th key={h} style={{ padding: '8px 12px', textAlign: 'left', fontSize: '9px', fontWeight: 700, color: DS.color.graphiteMuted, textTransform: 'uppercase', letterSpacing: '0.06em', borderBottom: `1px solid ${DS.color.borderLight}` }}>{h}</th>)}</tr></thead>
                        <tbody>{creationResults.map((r, i) => <tr key={i} style={{ borderBottom: `1px solid ${DS.color.borderLight}`, backgroundColor: i % 2 === 0 ? DS.color.surface : DS.color.surfaceAlt }}>
                          <td style={{ padding: '8px 12px', fontWeight: 500 }}>{r.email}</td>
                          <td style={{ padding: '8px 12px', fontFamily: 'monospace', fontSize: '11px', backgroundColor: DS.color.surfaceAlt }}>{r.password}</td>
                          <td style={{ padding: '8px 12px' }}><span style={{ padding: '2px 8px', fontSize: '10px', fontWeight: 700, backgroundColor: r.success ? DS.color.okBg : DS.color.dangerBg, color: r.success ? DS.color.ok : DS.color.danger }}>{r.success ? '✓ Успех' : '✗ Грешка'}</span></td>
                          <td style={{ padding: '8px 12px', fontSize: '11px', color: DS.color.graphiteLight }}>{r.message}</td>
                        </tr>)}</tbody>
                      </table>
                    </div>
                  </div>
                )}
              </div>
            </Card>
          )}

          {/* ═══ TAB: MANAGE ═══ */}
          {activeTab === 'manage' && (
            <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
              <Card>
                <SectionHeader icon="users" title={`Мениджъри (${allManagers.length})`} />
                <div style={{ overflowX: 'auto' }}>
                  <table style={{ width: '100%', borderCollapse: 'collapse', fontFamily: DS.font, fontSize: '12px' }}>
                    <thead><tr style={{ backgroundColor: DS.color.cardHeader }}>{['Email', 'Име', 'Ресторант', 'Статус', ''].map(h => <th key={h} style={{ padding: '8px 12px', textAlign: 'left', fontSize: '9px', fontWeight: 700, color: DS.color.graphiteMuted, textTransform: 'uppercase', letterSpacing: '0.06em', borderBottom: `1px solid ${DS.color.borderLight}` }}>{h}</th>)}</tr></thead>
                    <tbody>{allManagers.map((m, i) => <tr key={m.id} style={{ borderBottom: `1px solid ${DS.color.borderLight}`, backgroundColor: i % 2 === 0 ? DS.color.surface : DS.color.surfaceAlt }}>
                      <td style={{ padding: '8px 12px', fontWeight: 500 }}>{m.email}</td>
                      <td style={{ padding: '8px 12px' }}>{m.full_name || '—'}</td>
                      <td style={{ padding: '8px 12px' }}>{m.restaurants?.name || <span style={{ color: DS.color.graphiteMuted, fontStyle: 'italic' }}>Няма</span>}</td>
                      <td style={{ padding: '8px 12px' }}><span style={{ padding: '2px 8px', fontSize: '10px', fontWeight: 700, backgroundColor: m.active ? DS.color.okBg : DS.color.dangerBg, color: m.active ? DS.color.ok : DS.color.danger }}>{m.active ? 'Активен' : 'Неактивен'}</span></td>
                      <td style={{ padding: '8px 12px' }}>
                        <div style={{ display: 'flex', gap: '4px' }}>
                          <DSButton onClick={() => setSelectedManager(m)} variant="outline" icon="key" size="sm">Парола</DSButton>
                          {m.restaurants && <DSButton onClick={() => { setEditingRestaurant(m.restaurants); setNewRestaurantName(m.restaurants.name) }} variant="info" icon="edit" size="sm">Ресторант</DSButton>}
                        </div>
                      </td>
                    </tr>)}</tbody>
                  </table>
                </div>
              </Card>
              {selectedManager && (
                <Card style={{ border: `2px solid ${DS.color.primary}`, animation: 'slideUp 0.3s ease' }}>
                  <SectionHeader icon="key" title={`Смяна на парола — ${selectedManager.email}`} />
                  <div style={{ padding: pad }}>
                    <div style={{ display: 'flex', gap: '8px', marginBottom: '12px', flexDirection: isMobile ? 'column' : 'row' }}>
                      <DSInput label="Нова парола" type="text" value={newPassword} onChange={e => setNewPassword(e.target.value)} placeholder="Въведи нова парола" />
                      <div style={{ display: 'flex', alignItems: 'flex-end' }}><DSButton onClick={() => setNewPassword(generatePassword())} variant="info">Генерирай</DSButton></div>
                    </div>
                    <div style={{ display: 'flex', gap: '8px' }}>
                      <DSButton onClick={handleResetPassword} disabled={loading || !newPassword} icon="save">{loading ? 'Променям...' : 'Промени'}</DSButton>
                      <DSButton onClick={() => { setSelectedManager(null); setNewPassword('') }} variant="ghost">Отказ</DSButton>
                    </div>
                  </div>
                </Card>
              )}
              {editingRestaurant && (
                <Card style={{ border: `2px solid ${DS.color.info}`, animation: 'slideUp 0.3s ease' }}>
                  <SectionHeader icon="edit" title="Редактиране на ресторант" color={DS.color.info} bg={DS.color.infoBg} />
                  <div style={{ padding: pad }}>
                    <DSInput label="Име на ресторант" value={newRestaurantName} onChange={e => setNewRestaurantName(e.target.value)} placeholder="..." />
                    <p style={{ fontSize: '11px', color: DS.color.graphiteMuted, margin: '6px 0 14px', fontFamily: DS.font }}>Текущо име: <strong>{editingRestaurant.name}</strong></p>
                    <div style={{ display: 'flex', gap: '8px' }}>
                      <DSButton onClick={handleUpdateRestaurantName} disabled={loading || !newRestaurantName.trim()} variant="info" icon="save">{loading ? 'Променям...' : 'Промени'}</DSButton>
                      <DSButton onClick={() => { setEditingRestaurant(null); setNewRestaurantName('') }} variant="ghost">Отказ</DSButton>
                    </div>
                  </div>
                </Card>
              )}
            </div>
          )}

          {/* ═══ TAB: TEMPLATES ═══ */}
          {activeTab === 'templates' && (
            <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
              <Card>
                <SectionHeader icon="clipboard" title="Създай template" />
                <div style={{ padding: pad, display: 'flex', flexDirection: 'column', gap: '12px' }}>
                  <DSInput label="Име на template" value={templateName} onChange={e => setTemplateName(e.target.value)} placeholder="Контрол на работно облекло" />
                  <DSInput label="Описание" value={templateDescription} onChange={e => setTemplateDescription(e.target.value)} placeholder="Проверка на хигиена и облекло" />
                  <div>
                    <label style={{ display: 'block', fontFamily: DS.font, fontSize: '11px', fontWeight: 600, color: DS.color.graphiteLight, textTransform: 'uppercase', letterSpacing: '0.04em', marginBottom: '6px' }}>Отдели</label>
                    <div style={{ display: 'flex', gap: '6px', flexWrap: 'wrap' }}>
                      {departments.map(d => { const sel = selectedDepartments.includes(d); return <button key={d} onClick={() => setSelectedDepartments(sel ? selectedDepartments.filter(x => x !== d) : [...selectedDepartments, d])} style={{ padding: '6px 14px', backgroundColor: sel ? DS.color.primary : DS.color.surfaceAlt, color: sel ? '#fff' : DS.color.graphiteMed, border: `1.5px solid ${sel ? DS.color.primary : DS.color.borderLight}`, borderRadius: DS.radius, cursor: 'pointer', fontFamily: DS.font, fontSize: '12px', fontWeight: 600, transition: 'all 150ms' }}>{sel && '✓ '}{d}</button> })}
                    </div>
                  </div>
                  <div>
                    <label style={{ display: 'block', fontFamily: DS.font, fontSize: '11px', fontWeight: 600, color: DS.color.graphiteLight, textTransform: 'uppercase', letterSpacing: '0.04em', marginBottom: '6px' }}>JSON Config</label>
                    <textarea value={templateConfig} onChange={e => setTemplateConfig(e.target.value)} placeholder='{"type":"table","columns":[...]}' style={{ ...inputBase(false), minHeight: '160px', resize: 'vertical', fontFamily: "'DM Sans', monospace" }} />
                  </div>
                  <DSButton onClick={handleCreateTemplate} disabled={loading} icon="plus">{loading ? 'Създаване...' : 'Създай Template'}</DSButton>
                </div>
              </Card>
              {templates.length > 0 && (
                <Card>
                  <SectionHeader icon="clipboard" title={`Съществуващи (${templates.length})`} />
                  <div style={{ padding: '8px' }}>
                    {templates.map(t => (
                      <div key={t.id} style={{ padding: '12px', margin: '4px', backgroundColor: DS.color.surfaceAlt, border: `1px solid ${DS.color.borderLight}`, animation: 'ctrlFadeIn 0.3s ease' }}>
                        <div style={{ fontFamily: DS.font, fontSize: '14px', fontWeight: 700, color: DS.color.primary, marginBottom: '3px' }}>{t.name}</div>
                        {t.description && <div style={{ fontFamily: DS.font, fontSize: '12px', color: DS.color.graphiteLight, marginBottom: '6px' }}>{t.description}</div>}
                        <div style={{ display: 'flex', gap: '4px', flexWrap: 'wrap' }}>
                          {t.template_departments?.map((td, i) => <span key={i} style={{ padding: '2px 8px', backgroundColor: DS.color.primary, color: '#fff', fontSize: '10px', fontWeight: 700, fontFamily: DS.font }}>{td.department_name}</span>)}
                        </div>
                      </div>
                    ))}
                  </div>
                </Card>
              )}
            </div>
          )}

          {/* ═══ TAB: ASSIGN ═══ */}
          {activeTab === 'assign' && (
            <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
              <Card>
                <SectionHeader icon="link" title="Разпределяне" />
                <div style={{ padding: pad }}>
                  <DSSelect label="Ресторант" value={selectedRestaurant?.id || ''} onChange={e => { const r = restaurants.find(x => x.id === e.target.value); setSelectedRestaurant(r); if (r) loadAssignedTemplates(r.id) }}>
                    <option value="">— Избери ресторант —</option>
                    {restaurants.map(r => <option key={r.id} value={r.id}>{r.name} ({r.contact_email})</option>)}
                  </DSSelect>
                </div>
              </Card>
              {selectedRestaurant && (
                <>
                  <Card>
                    <SectionHeader icon="plus" title="Налични Templates" />
                    <div style={{ padding: '8px' }}>
                      {availableTemplates.length === 0 && <p style={{ padding: '12px', fontFamily: DS.font, fontSize: '12px', color: DS.color.graphiteMuted, fontStyle: 'italic' }}>Всички templates са разпределени</p>}
                      {availableTemplates.map(t => (
                        <div key={t.id} style={{ padding: '10px 12px', margin: '4px', backgroundColor: DS.color.surfaceAlt, border: `1px solid ${DS.color.borderLight}`, display: 'flex', justifyContent: 'space-between', alignItems: 'center', gap: '12px' }}>
                          <div><div style={{ fontFamily: DS.font, fontSize: '13px', fontWeight: 600 }}>{t.name}</div>{t.description && <div style={{ fontFamily: DS.font, fontSize: '11px', color: DS.color.graphiteLight }}>{t.description}</div>}</div>
                          <DSButton onClick={() => handleAssignTemplate(t.id)} icon="plus" size="sm">Добави</DSButton>
                        </div>
                      ))}
                    </div>
                  </Card>
                  <Card style={{ border: `2px solid ${DS.color.primary}` }}>
                    <SectionHeader icon="check" title="Разпределени" />
                    <div style={{ padding: '8px' }}>
                      {assignedTemplates.length === 0 && <p style={{ padding: '12px', fontFamily: DS.font, fontSize: '12px', color: DS.color.graphiteMuted, fontStyle: 'italic' }}>Няма</p>}
                      {assignedTemplates.map(a => (
                        <div key={a.id} style={{ padding: '10px 12px', margin: '4px', backgroundColor: DS.color.okBg, border: `1px solid ${DS.color.primary}`, display: 'flex', justifyContent: 'space-between', alignItems: 'center', gap: '12px' }}>
                          <span style={{ fontFamily: DS.font, fontSize: '13px', fontWeight: 600, color: DS.color.primary, display: 'flex', alignItems: 'center', gap: '6px' }}><Icon name="check" size={14} color={DS.color.primary} />{a.checklist_templates.name}</span>
                          <DSButton onClick={() => handleUnassignTemplate(a.id)} variant="outlineDanger" size="sm">Премахни</DSButton>
                        </div>
                      ))}
                    </div>
                  </Card>
                </>
              )}
            </div>
          )}
        </div>

        <div style={{ textAlign: 'center', padding: isMobile ? '16px 12px' : '20px 24px', color: DS.color.graphiteMuted, fontFamily: DS.font, fontSize: '11px', fontWeight: 500, borderTop: `1px solid ${DS.color.borderLight}`, marginTop: 'auto' }}>© 2026 Aladin Foods | by MG</div>
      </div>
    </>
  )
}

/* ═══════════════════════════════════════════════════════════════
   DASHBOARD
   ═══════════════════════════════════════════════════════════════ */
const Dashboard = ({ profile, onSignOut }) => {
  const { isMobile } = useResponsive()
  const pad = isMobile ? '12px' : '20px'
  const [currentView, setCurrentView] = useState('dashboard')
  const [selectedDepartment, setSelectedDepartment] = useState(null)
  const [departments, setDepartments] = useState([])
  const [loading, setLoading] = useState(false)
  const [showChecklists, setShowChecklists] = useState(false)
  const [now, setNow] = useState(new Date())
  const [isOnline, setIsOnline] = useState(navigator.onLine)
  const deptEmoji = DEPT_ICONS

  const restId = profile?.restaurant_id || profile?.restaurants?.id

  useEffect(() => { const t = setInterval(() => setNow(new Date()), 1000); return () => clearInterval(t) }, [])
  useEffect(() => { const on = () => setIsOnline(true); const off = () => setIsOnline(false); window.addEventListener('online', on); window.addEventListener('offline', off); return () => { window.removeEventListener('online', on); window.removeEventListener('offline', off) } }, [])
  useEffect(() => { if (profile?.role === 'manager' && restId) loadDepts() }, [profile])

  const loadDepts = async () => {
    if (!restId) return
    setLoading(true)
    try { const { data, error } = await supabase.from('departments').select('*').eq('restaurant_id', restId).eq('active', true).order('name'); if (error) throw error; setDepartments((data || []).map(d => ({ ...d, icon: deptEmoji[d.name] || null }))) }
    catch (e) { console.error('Error loading departments:', e) }
    finally { setLoading(false) }
  }

  // Ensure departments are loaded when entering checklists view
  const handleOpenChecklists = () => {
    setShowChecklists(true)
    if (departments.length === 0 && restId) loadDepts()
  }

  /* ═══ LAZY LOADING FALLBACK ═══ */
  const LazyFallback = () => (
    <div style={{ minHeight: '100vh', backgroundColor: DS.color.bg, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
      <div style={{ textAlign: 'center' }}>
        <div style={{ width: 36, height: 36, border: `3px solid ${DS.color.borderLight}`, borderTop: `3px solid ${DS.color.primary}`, borderRadius: '50%', animation: 'ctrlSpin 0.8s linear infinite', margin: '0 auto 12px' }} />
        <p style={{ fontFamily: DS.font, fontSize: '12px', color: DS.color.graphiteLight, fontWeight: 600 }}>Зареждане...</p>
      </div>
    </div>
  )

  if (currentView === 'admin') return <SuperAdminPanel onBack={() => setCurrentView('dashboard')} />
  if (currentView === 'reports') return <Suspense fallback={<LazyFallback />}><ReportsAdminPanel onBack={() => setCurrentView('dashboard')} /></Suspense>
  if (currentView === 'notifications') return <Suspense fallback={<LazyFallback />}><NotificationsPanel onBack={() => setCurrentView('dashboard')} restaurantId={restId} userId={profile?.id} /></Suspense>
  if (currentView === 'notification-settings') return <NotificationSettings onBack={() => setCurrentView('dashboard')} restaurantId={restId} />
  if (currentView === 'all-history') return <Suspense fallback={<LazyFallback />}><AllSubmissionsHistory restaurantId={restId} onBack={() => setCurrentView('dashboard')} /></Suspense>
  if (currentView === 'recipes') return <Suspense fallback={<LazyFallback />}><RecipesManager onBack={() => setCurrentView('dashboard')} /></Suspense>
  if (currentView === 'incoming-control') return <Suspense fallback={<LazyFallback />}><IncomingMaterialsControl profile={profile} onBack={() => setCurrentView('dashboard')} /></Suspense>
  if (showChecklists && selectedDepartment && profile?.role === 'manager') return <Suspense fallback={<LazyFallback />}><DepartmentView department={selectedDepartment} restaurantId={restId} onBack={() => { setSelectedDepartment(null); setShowChecklists(false) }} /></Suspense>

  const roleLabel = profile?.role === 'super_admin' ? 'Super Admin' : profile?.role === 'reports_admin' ? 'Reports Admin' : 'Мениджър'
  const quickActions = []
  if (profile?.role === 'super_admin') quickActions.push({ id: 'admin', label: 'Admin Panel', icon: 'settings', variant: 'primary' })
  if (profile?.role === 'super_admin' || profile?.role === 'reports_admin') quickActions.push({ id: 'reports', label: 'Reports', icon: 'chart', variant: 'info' })
  quickActions.push({ id: 'all-history', label: 'Пълна история', icon: 'history', variant: 'primary' })
  quickActions.push({ id: 'notifications', label: 'Известия', icon: 'bell', variant: 'warning' })

  return (
    <>
      <style>{GLOBAL_CSS}</style>
      <div style={{ minHeight: '100vh', backgroundColor: DS.color.bg, fontFamily: DS.font, color: DS.color.graphite, display: 'flex', flexDirection: 'column' }}>

        {/* ═══ DARK TOP BAR ═══ */}
        <div style={{ position: 'sticky', top: 0, zIndex: 100, backgroundColor: DS.color.graphite, padding: '0 16px', display: 'flex', alignItems: 'center', justifyContent: 'space-between', height: '48px', boxShadow: '0 2px 8px rgba(0,0,0,0.2)' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
            <span style={{ fontFamily: DS.font, fontSize: '13px', fontWeight: 700, color: 'rgba(255,255,255,0.85)' }}>{profile?.restaurants?.name || 'Control Room'}</span>
            <div style={{ display: 'flex', alignItems: 'center', gap: '6px', marginLeft: '8px' }}>
              <div style={{ width: 7, height: 7, borderRadius: '50%', backgroundColor: isOnline ? '#4ADE80' : '#F87171' }} />
              <span style={{ color: 'rgba(255,255,255,0.4)', fontSize: '10px', fontWeight: 600, fontFamily: DS.font }}>{isOnline ? 'Online' : 'Offline'}</span>
            </div>
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
            <span style={{ fontFamily: DS.font, fontSize: '11px', fontWeight: 500, color: 'rgba(255,255,255,0.35)' }}>
              {now.toLocaleString('bg-BG', { hour: '2-digit', minute: '2-digit', ...(isMobile ? {} : { second: '2-digit', day: '2-digit', month: '2-digit', year: 'numeric' }), hour12: false })}
            </span>
            <button onClick={onSignOut} style={{ display: 'flex', alignItems: 'center', gap: '4px', padding: '6px 10px', backgroundColor: 'rgba(197,48,48,0.15)', border: '1px solid rgba(197,48,48,0.25)', borderRadius: DS.radius, color: 'rgba(255,180,180,0.9)', cursor: 'pointer', fontFamily: DS.font, fontSize: '11px', fontWeight: 600 }}>
              <Icon name="logout" size={13} color="rgba(255,180,180,0.9)" />{!isMobile && 'Изход'}
            </button>
          </div>
        </div>

        <div style={{ maxWidth: '1000px', margin: '0 auto', padding: pad, flex: 1, width: '100%' }}>

          {/* ═══ LOGO + TITLE CARD — exact match to production sheets ═══ */}
          <div style={{ display: 'flex', alignItems: 'center', gap: isMobile ? '10px' : '14px', marginBottom: '16px', padding: '0 2px' }}>
            <img src={LOGO_URL} alt="Aladin Foods" style={{ height: isMobile ? '36px' : '48px', objectFit: 'contain', flexShrink: 0 }} onError={e => { e.target.style.display = 'none' }} />
            <div style={{ minWidth: 0 }}>
              <h1 style={{ fontSize: isMobile ? '16px' : '22px', fontWeight: 700, color: DS.color.primary, margin: 0, letterSpacing: '-0.01em', lineHeight: 1.2, textTransform: 'uppercase', fontFamily: DS.font }}>
                {profile?.restaurants?.name || 'Control Room'}
              </h1>
              <p style={{ fontFamily: DS.font, fontSize: isMobile ? '10px' : '12px', color: DS.color.graphiteLight, fontWeight: 500, margin: '3px 0 0', letterSpacing: '0.02em' }}>
                Добре дошъл, {profile?.full_name || profile?.email}
              </p>
            </div>
          </div>

          {/* Role + info strip */}
          <Card style={{ marginBottom: '12px' }}>
            <div style={{ padding: '10px 16px', display: 'flex', alignItems: 'center', justifyContent: 'space-between', flexWrap: 'wrap', gap: '8px' }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                <span style={{ padding: '3px 10px', backgroundColor: DS.color.okBg, color: DS.color.primary, fontSize: '10px', fontWeight: 700, fontFamily: DS.font, textTransform: 'uppercase', letterSpacing: '0.04em' }}>{roleLabel}</span>
                {profile?.email && <span style={{ fontFamily: DS.font, fontSize: '11px', color: DS.color.graphiteMuted }}>{profile.email}</span>}
              </div>
              <div style={{ display: 'flex', gap: '6px', flexWrap: 'wrap' }}>
                {quickActions.map(a => (
                  <DSButton key={a.id} onClick={() => setCurrentView(a.id)} variant={a.variant} icon={a.icon} size="sm" style={{ position: 'relative' }}>
                    {a.label}
                    {a.id === 'notifications' && <NotificationBadge restaurantId={restId} />}
                  </DSButton>
                ))}
              </div>
            </div>
          </Card>

          {/* ═══ MAIN CARDS — Чек листи / Рецепти / Входящ контрол ═══ */}
          {profile?.role === 'manager' && !showChecklists && (
            <div style={{ display: 'grid', gridTemplateColumns: isMobile ? '1fr' : 'repeat(2, 1fr)', gap: '12px', marginBottom: '16px' }}>
              {[
                { id: 'checklists', iconSrc: CHECKLIST_ICON, label: 'Чек листи', desc: 'Управление по отдели', action: () => handleOpenChecklists() },
                { id: 'recipes', iconSrc: RECIPE_ICON, label: 'Рецепти', desc: 'Професионални рецепти', action: () => setCurrentView('recipes') },
              ].map((c, i) => (
                <Card key={c.id} style={{ cursor: 'pointer', transition: 'all 200ms' }}>
                  <div onClick={c.action} style={{ padding: isMobile ? '24px 16px' : '32px 20px', textAlign: 'center' }}
                    onMouseEnter={e => { e.currentTarget.parentElement.style.boxShadow = DS.shadow.glow; e.currentTarget.parentElement.style.borderColor = DS.color.primary }}
                    onMouseLeave={e => { e.currentTarget.parentElement.style.boxShadow = DS.shadow.sm; e.currentTarget.parentElement.style.borderColor = DS.color.borderLight }}>
                    <img src={c.iconSrc} alt={c.label} style={{ width: '56px', height: '56px', objectFit: 'contain', marginBottom: '10px' }} />
                    <h3 style={{ margin: '0 0 4px', fontSize: '16px', fontWeight: 700, color: DS.color.primary, fontFamily: DS.font, textTransform: 'uppercase', letterSpacing: '0.02em' }}>{c.label}</h3>
                    <p style={{ margin: 0, fontFamily: DS.font, fontSize: '11px', color: DS.color.graphiteLight, fontWeight: 500 }}>{c.desc}</p>
                  </div>
                </Card>
              ))}
            </div>
          )}

          {/* ═══ DEPARTMENTS GRID ═══ */}
          {profile?.role === 'manager' && showChecklists && !selectedDepartment && (
            <>
              <Card style={{ marginBottom: '12px' }}>
                <div style={{ padding: '10px 16px', display: 'flex', alignItems: 'center', gap: '12px' }}>
                  <DSButton onClick={() => setShowChecklists(false)} variant="ghost" icon="back" size="sm">Назад</DSButton>
                  <span style={{ fontFamily: DS.font, fontSize: '12px', fontWeight: 600, color: DS.color.graphiteMuted, textTransform: 'uppercase', letterSpacing: '0.04em' }}>Избери отдел</span>
                </div>
              </Card>
              <div style={{ display: 'grid', gridTemplateColumns: isMobile ? '1fr 1fr' : 'repeat(auto-fit, minmax(200px, 1fr))', gap: '12px' }}>
                {loading ? (
                  <div style={{ gridColumn: '1 / -1', padding: '40px', textAlign: 'center' }}>
                    <div style={{ width: 36, height: 36, border: `3px solid ${DS.color.borderLight}`, borderTop: `3px solid ${DS.color.primary}`, borderRadius: '50%', animation: 'ctrlSpin 0.8s linear infinite', margin: '0 auto 12px' }} />
                    <p style={{ fontFamily: DS.font, fontSize: '12px', color: DS.color.graphiteLight, margin: 0, fontWeight: 600 }}>Зареждане на отдели...</p>
                  </div>
                ) : departments.length === 0 ? (
                  <div style={{ gridColumn: '1 / -1', padding: '40px', textAlign: 'center' }}>
                    <p style={{ fontFamily: DS.font, fontSize: '13px', color: DS.color.graphiteMuted }}>Няма намерени отдели</p>
                  </div>
                ) : departments.map(dept => (
                  <Card key={dept.id} style={{ cursor: 'pointer', transition: 'all 200ms' }}>
                    <div onClick={() => setSelectedDepartment(dept)} style={{ padding: isMobile ? '20px 12px' : '24px 16px', textAlign: 'center' }}
                      onMouseEnter={e => { e.currentTarget.parentElement.style.boxShadow = DS.shadow.glow; e.currentTarget.parentElement.style.borderColor = DS.color.primary }}
                      onMouseLeave={e => { e.currentTarget.parentElement.style.boxShadow = DS.shadow.sm; e.currentTarget.parentElement.style.borderColor = DS.color.borderLight }}>
                      {dept.icon ? <img src={dept.icon} alt={dept.name} style={{ width: '48px', height: '48px', objectFit: 'contain', marginBottom: '8px' }} /> : <div style={{ fontSize: '36px', marginBottom: '8px', lineHeight: 1 }}>📋</div>}
                      <h3 style={{ margin: '0 0 8px', fontSize: '15px', fontWeight: 700, color: DS.color.primary, fontFamily: DS.font, textTransform: 'uppercase' }}>{dept.name}</h3>
                      <span style={{ display: 'inline-flex', alignItems: 'center', gap: '4px', padding: '6px 14px', backgroundColor: DS.color.primary, color: '#fff', fontFamily: DS.font, fontSize: '11px', fontWeight: 600 }}>
                        <Icon name="clipboard" size={12} color="#fff" /> Отвори
                      </span>
                    </div>
                  </Card>
                ))
                }
              </div>
            </>
          )}
        </div>

        {/* ═══ FOOTER ═══ */}
        <div style={{ textAlign: 'center', padding: isMobile ? '16px 12px' : '20px 24px', color: DS.color.graphiteMuted, fontFamily: DS.font, fontSize: '11px', fontWeight: 500, borderTop: `1px solid ${DS.color.borderLight}`, marginTop: 'auto' }}>© 2026 Aladin Foods | by MG</div>
      </div>
    </>
  )
}

/* ═══════════════════════════════════════════════════════════════
   APP CONTENT & PROVIDERS
   ═══════════════════════════════════════════════════════════════ */
function AppContent() {
  const { user, profile, loading, signIn, signOut } = useAuth()
  if (loading) return <LoadingScreen />
  if (!user) return <LoginScreen onLogin={signIn} />
  return <Dashboard profile={profile} onSignOut={signOut} />
}

function App() {
  return (
    <AuthProvider>
      <LanguageProvider>
        <AppContent />
      </LanguageProvider>
    </AuthProvider>
  )
}

export default App